INSERT INTO field_note (id, location_id, crop_cycle_id, note_type, note_date, content, status) VALUES
('b0000000-0000-0000-0000-200000000001', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000040', 'observation', '2025-10-15', 'Maize germination looks good on Plot A. Stand count approximately 85%. Some gaps in northeast corner.', 'published'),
('b0000000-0000-0000-0000-200000000002', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000040', 'recommendation', '2025-11-01', 'Fall armyworm pressure increasing. Recommend scouting every 3 days and applying biopesticide.', 'published'),
('b0000000-0000-0000-0000-200000000003', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000040', 'observation', '2025-12-01', 'Heavy rains caused lodging in 15% of Plot A maize. Drainage channels need improvement.', 'published'),
('b0000000-0000-0000-0000-200000000004', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000043', 'observation', '2025-11-10', 'Bean mosaic virus affecting about 10% of Plot C beans. Removed affected plants.', 'published'),
('b0000000-0000-0000-0000-200000000005', 'a0000000-0000-0000-0000-000000000001', NULL, 'observation', '2025-12-15', 'Stored harvested maize at 13% moisture content. Storage conditions good.', 'published'),
('b0000000-0000-0000-0000-200000000006', 'a0000000-0000-0000-0000-000000000001', NULL, 'recommendation', '2026-01-05', 'Planning next season: increase bean area by 0.5ha. Consider intercropping with maize.', 'published'),
('b0000000-0000-0000-0000-200000000007', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000041', 'observation', '2026-01-20', 'New maize planted on Plot A. Germination uniform. Supplemental irrigation applied.', 'published'),
('b0000000-0000-0000-0000-200000000008', 'a0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000044', 'observation', '2026-02-15', 'Sweet potato harvest good despite dry spell. Tubers smaller but quality excellent.', 'published'),
('b0000000-0000-0000-0000-200000000009', 'a0000000-0000-0000-0000-000000000001', NULL, 'observation', '2026-02-25', 'Theft incident at storage shed. Lost approximately 200kg of dried beans.', 'published'),
('b0000000-0000-0000-0000-200000000010', 'a0000000-0000-0000-0000-000000000001', NULL, 'recommendation', '2026-03-01', 'End of season review: Overall production above regional average despite weather challenges.', 'published'),
('b0000000-0000-0000-0000-200000000011', 'a0000000-0000-0000-0000-000000000001', NULL, 'observation', '2026-03-15', 'Cassava harvest complete. Good yields. Met with buyer - satisfied with quality.', 'published'),
('b0000000-0000-0000-0000-200000000012', 'a0000000-0000-0000-0000-000000000001', NULL, 'recommendation', '2026-03-30', 'Season summary: Total revenue $35,682. Total expenses $4,485. Net profit strong.', 'published')
